bad_example:
// Callee must defensively handle null
public double xProjection(Point p1, Point p2) {
    if (p1 == null || p2 == null)
        throw new InvalidArgumentException("p1 and p2 required");
    return (p2.x - p1.x) * 1.5;
}

// Or worse: no guard, NPE at runtime
calculator.xProjection(null, new Point(1, 1));

CODE_EXAMPLE:
// Contract: nulls are not allowed; callers are responsible
public double xProjection(@NonNull Point p1, @NonNull Point p2) {
    return (p2.x - p1.x) * 1.5;
}

// Caller always provides real objects
double result = calculator.xProjection(new Point(0, 0), new Point(3, 4));

UNIT_TEST_EXAMPLE:
@Test
public void xProjection_computesCorrectly() {
    MetricsCalculator calc = new MetricsCalculator();
    assertEquals(4.5, calc.xProjection(new Point(0, 0), new Point(3, 0)), 0.001);
}

@Test
public void xProjection_throwsForNullArgument() {
    MetricsCalculator calc = new MetricsCalculator();
    assertThrows(NullPointerException.class, () -> calc.xProjection(null, new Point(1, 0)));
}
